class Solution {
    public int minimizeXor(int num1, int num2) {
        int setBitsNum2 = Integer.bitCount(num2);
        int x = 0;
        for (int i = 0; i < 30; i++) {
            if (((num1 >> i) & 1) == 1) {
                x |= 1 << i;
                setBitsNum2--;
                if (setBitsNum2 == 0) break;
            }
        }
        return x;
    }
}
